    // The workflow reads from /tmp/commits.txt — we inject it via a pre-step
    // by modifying the workflow to use our fixture
    // Instead, we create a custom workflow that inlines the git log
    const workflowContent = `name: Semantic Version Bumper

on:
  push:
    branches:
      - main
      - master
  workflow_dispatch:

permissions:
  contents: write

jobs:
  test:
    name: Run Tests
    runs-on: ubuntu-latest
    steps:
      - name: Checkout
        uses: actions/checkout@v4

      - name: Setup Bun
        uses: oven-sh/setup-bun@v2
        with:
          bun-version: latest

      - name: Install dependencies
        run: bun install

      - name: Run unit tests
        run: bun test src/version-bumper.test.ts

  bump-version:
    name: Bump Version
    runs-on: ubuntu-latest
    needs: test
    steps:
      - name: Checkout
        uses: actions/checkout@v4

      - name: Setup Bun
        uses: oven-sh/setup-bun@v2
        with:
          bun-version: latest

      - name: Install dependencies
        run: bun install

      - name: Write fixture git log
        run: |
          cat > /tmp/commits.txt << 'GITLOG'
${tc.gitLog}
